// 1. Get the dynamic data from the MITRE parsing node
const canonicalTarget = $('Parse MITRE Aliases').first().json.canonical_name;
const aptAliases = $('Parse MITRE Aliases').first().json.apt_dictionary;

const validPulses = [];

// 2. Implement the TRAIL Alias Isolation Logic
for (const item of $input.all()) {
  const pulse = item.json;
  if (!pulse.indicators) continue;

  const tags = pulse.tags ? pulse.tags.map(t => t.toLowerCase()) : [];
  let hasConflict = false;

  // Check the pulse tags against the massive MITRE dictionary
  for (const [canonical, aliases] of Object.entries(aptAliases)) {
    // Skip checking aliases for our actual target
    if (canonical === canonicalTarget) continue; 

    // If the pulse has a tag that matches ANOTHER group's alias, flag it
    const containsOtherApt = aliases.some(alias => tags.includes(alias));
    if (containsOtherApt) {
      hasConflict = true;
      break; 
    }
  }

  // Paper Rule: Ignore if it has multiple valid APT aliases as tags
  if (hasConflict) continue;

  validPulses.push(pulse);
}

// 3. Implement the TRAIL Threshold Logic (25 events minimum)
if (validPulses.length < 25) {
   return []; // Gracefully stops the workflow if not enough clean data exists
}

// 4. Extract IOCs for Neo4j
const allIOCs = [];
for(const pulse of validPulses) {
  const iocs = pulse.indicators
    .filter(i => i.type === 'domain' || i.type === 'hostname' || i.type === 'IPv4' || i.type === 'URL')
    .map(i => ({
       event_id: pulse.id,
       event_name: pulse.name,
       apt_label: canonicalTarget, 
       ioc: i.indicator,
       type: (i.type === 'hostname') ? 'domain' : i.type
    }));
  allIOCs.push(...iocs);
}

return allIOCs;

// TRAIL Logic: Map Relationships correctly
const input = $input.all()[0].json;
const meta = $('Split in Batches').first().json;

if (!input.passive_dns) return [];

return input.passive_dns
  .filter(record => record.record_type === 'A')
  .map(record => {
     let domain, ip;
     if (meta.type === 'domain') {
       domain = meta.ioc;
       ip = record.address;
     } else {
       domain = record.hostname;
       ip = meta.ioc;
     }
     return {
       event_name: meta.event_name, 
       event_id: meta.event_id,
       apt_label: meta.apt_label,
       primary_domain: domain,
       secondary_ip: ip,
       first_seen: record.first,
       last_seen: record.last
     };
  });

// Simple Formatter for URLs (Direct Pass-through)
const meta = $('Split in Batches').first().json;

return [{
  type: 'URL',
  event_name: meta.event_name,
  event_id: meta.event_id,
  apt_label: meta.apt_label,
  url: meta.ioc
}];

