// 1. Get the raw input
const rawUrl = $json.chatInput;

// 2. Remove the protocol (handle both http and hxxp)
const noProtocol = rawUrl.replace(/^h[tx]{2}ps?:\/\//i, '');

// 3. Extract just the domain (everything before the first '/')
const domain = noProtocol.split('/')[0];

// 4. Return the cleaned domain
return {
  domain: domain,
  type: 'domain'
};

// 1. Get the raw enrichment data from the OTX node
const input = $input.all()[0].json;

// 2. Identify the target IOC from the Chat Trigger instead of Batching
const targetIOC = $('When chat message received').first().json.chatInput;

if (!input.passive_dns) return [];

// 3. Prepare the data for Neo4j
return input.passive_dns
  // Only keep 'A' records AND filter out dead NXDOMAINs
  .filter(record => record.record_type === 'A' && record.address !== 'NXDOMAIN')
  .map(record => {
     return {
       // Create a generic Discovery event for the new IOC
       event_name: "AI Agent Discovery: " + targetIOC,
       event_id: "discovery-" + targetIOC,
       apt_label: "Pending Attribution", 
       primary_domain: targetIOC,
       secondary_ip: record.address,
       first_seen: record.first,
       last_seen: record.last
     };
  });

// ==========================================
// 1. TYPE YOUR TARGET APT RIGHT HERE!
// ==========================================
const TARGET_APT = "APT29"; 

// 2. Get the raw input from the HTTP node
let rawInput = $input.first().json;
let mitreData;

// 3. Force n8n to parse GitHub's plain text as a JSON object
if (rawInput.data && typeof rawInput.data === 'string') {
  mitreData = JSON.parse(rawInput.data);
} else if (rawInput.data && typeof rawInput.data === 'object') {
  mitreData = rawInput.data;
} else {
  mitreData = rawInput;
}

// Safety check for the MITRE data
if (!mitreData.objects) {
  throw new Error("MITRE data is missing! The JSON parsing failed.");
}

const userInput = TARGET_APT.toLowerCase();
const aptAliases = {};
let canonicalTarget = TARGET_APT; 

// 4. Filter the massive JSON for Threat Actors (Intrusion Sets)
const intrusionSets = mitreData.objects.filter(obj => obj.type === 'intrusion-set');

// 5. Build the dynamic dictionary
for (const group of intrusionSets) {
  const canonicalName = group.name;
  let aliases = group.aliases || [];

  // Add the official name to the alias list so it matches itself
  aliases.push(canonicalName); 
  const lowerAliases = aliases.map(a => a.toLowerCase());

  aptAliases[canonicalName] = lowerAliases;

  // Check if the user's input matches ANY alias in this group
  if (lowerAliases.includes(userInput)) {
    canonicalTarget = canonicalName;
  }
}

// 6. Output the official name and the full dictionary
return {
  canonical_name: canonicalTarget,
  apt_dictionary: aptAliases
};
